sysevent_script_action.script:
// Copyrights belong to Discover Technologies LLC. © 2019 Discover Technologies LLC
// Script Continued Below
// RAJ - this event starts the process to generate a process from a Tasker Tree

// STRY0037846 Check if process template name exisits
function checkIfNameExists(name, count){
	var templateName = name;

	var gr = new GlideAggregate('x_153465_discovert_discover_routing_template');
	gr.addQuery('template_name', templateName);
	gr.query();

	if(gr.next()){

		templateName = current.short_description +  ' - Copy (' + count +')';
		templateName = checkIfNameExists(templateName , count+1);
	}

	return templateName;
}

function getOwnerName(ownerId){
	var name = '';
	var gr = new GlideRecordSecure('sys_user');
	gr.addQuery('sys_id', ownerId);
	gr.query();
	if(gr.next()){
		name =  gr.name;
	}

	return name;
}

var recCreateTemp = new GlideRecordSecure('x_153465_discovert_discover_routing_template');
recCreateTemp.initialize();

// Set the Generate From TaskerInstance associated with the process template
recCreateTemp.setValue ( 'original_tasker_saved_to_process', current.sys_id );
// that is it, workflow is still going to fire off the insert of the Process Instance table

recCreateTemp.process_owner = event.parm2;
recCreateTemp.template_name = checkIfNameExists(current.short_description , 1);
recCreateTemp.u_process_id = recCreateTemp.template_name + ' - Personal Template - ' + getOwnerName(event.parm2);
recCreateTemp.short_description = current.short_description;
recCreateTemp.u_objective = current.u_objective;
recCreateTemp.description = current.instructions;
recCreateTemp.process_level = 'my_process';
recCreateTemp.insert();
